  1→/**
  2→ * Claude Code CLI Provider
  3→ * Implements the AI provider interface for Claude Code CLI
  4→ */
  5→
  6→import { DEFAULT_TIMEOUT_MS } from "@shared/constants";
  7→import type { Usage } from "@shared/types/evaluation";
  8→import { claudeLogger } from "@shared/utils/logger";
  9→import { BaseProvider } from "./base-provider";
 10→import { checkCliAvailability } from "./cli-checker";
 11→import type {
 12→	IProviderInvokeOptions,
 13→	IProviderResponse,
 14→	ProviderName,
 15→} from "./types";
 16→
 17→/**
 18→ * Claude CLI response format
 19→ */
 20→interface ClaudeCLIResponse {
 21→	result?: string;
 22→	session_id?: string;
 23→	total_cost_usd?: number;
 24→	duration_ms?: number;
 25→	usage?: Usage;
 26→}
 27→
 28→/**
 29→ * Claude Code CLI provider implementation
 30→ */
 31→export class ClaudeProvider extends BaseProvider {
 32→	readonly name: ProviderName = "claude";
 33→	readonly displayName = "Claude Code";
 34→
 35→	/**
 36→	 * Check if Claude CLI is available
 37→	 */
 38→	async isAvailable(): Promise<boolean> {
 39→		return checkCliAvailability("claude", ["--version"], this.displayName);
 40→	}
 41→
 42→	/**
 43→	 * Invoke Claude CLI with a prompt
 44→	 */
 45→	async invoke(
 46→		prompt: string,
 47→		options: IProviderInvokeOptions = {},
 48→	): Promise<IProviderResponse> {
 49→		const {
 50→			verbose = false,
 51→			timeout = DEFAULT_TIMEOUT_MS,
 52→			cwd,
 53→			writeMode = false,
 54→		} = options;
 55→
 56→		// Note: prompt is passed via stdin to avoid E2BIG errors on large prompts
 57→		const args = [
 58→			"-p",
 59→			"--output-format",
 60→			"json",
 61→			"--no-session-persistence",
 62→			"--disable-slash-commands",
 63→		];
 64→
 65→		if (writeMode) {
 66→			args.push("--dangerously-skip-permissions");
 67→		}
 68→
 69→		if (verbose) {
 70→			claudeLogger.log(`\nStarting API call...`);
 71→			claudeLogger.log(`Prompt length: ${prompt.length} chars`);
 72→			claudeLogger.log(
 73→				`Timeout: ${timeout}ms (${(timeout / 1000).toFixed(1)}s)`,
 74→			);
 75→			if (cwd) {
 76→				claudeLogger.log(`Working directory: ${cwd}`);
 77→			}
 78→			claudeLogger.log(
 79→				`Command: claude -p --output-format json --no-session-persistence (prompt via stdin)`,
 80→			);
 81→			claudeLogger.log(`Spawning process...`);
 82→		}
 83→
 84→		const startTime = Date.now();
 85→
 86→		const proc = Bun.spawn(["claude", ...args], {
 87→			stdin: "pipe",
 88→			stdout: "pipe",
 89→			stderr: "pipe",
 90→			env: process.env,
 91→			cwd: cwd || process.cwd(),
 92→		});
 93→
 94→		if (verbose) {
 95→			claudeLogger.log(`Process spawned (PID: ${proc.pid})`);
 96→		}
 97→
 98→		// Write prompt to stdin and close the stream
 99→		proc.stdin.write(prompt);
100→		await proc.stdin.end();
101→
102→		if (verbose) {
103→			claudeLogger.log(`Wrote ${prompt.length} chars to stdin`);
104→			claudeLogger.log(`Waiting for response...`);
105→		}
106→
107→		// Progress indicator for long operations
108→		let progressInterval: ReturnType<typeof setInterval> | undefined;
109→		if (verbose) {
110→			progressInterval = setInterval(() => {
111→				const elapsed = Date.now() - startTime;
112→				const remaining = timeout - elapsed;
113→				claudeLogger.log(
114→					`Still waiting... ${(elapsed / 1000).toFixed(1)}s elapsed, ${(remaining / 1000).toFixed(1)}s remaining`,
115→				);
116→			}, 5000);
117→		}
118→
119→		// Set up timeout
120→		const timeoutPromise = this.createTimeoutPromise<[string, string, number]>(
121→			timeout,
122→			() => {
123→				if (progressInterval) clearInterval(progressInterval);
124→				proc.kill();
125→			},
126→			startTime,
127→		);
128→
129→		try {
130→			const [stdout, stderr, exitCode] = await Promise.race([
131→				Promise.all([
132→					new Response(proc.stdout).text(),
133→					new Response(proc.stderr).text(),
134→					proc.exited,
135→				]),
136→				timeoutPromise,
137→			]);
138→
139→			if (progressInterval) clearInterval(progressInterval);
140→
141→			const elapsed = Date.now() - startTime;
142→			if (verbose) {
143→				claudeLogger.log(
144→					`Process exited with code ${exitCode} after ${(elapsed / 1000).toFixed(1)}s`,
145→				);
146→				claudeLogger.log(
147→					`stdout size: ${(stdout.length / 1024).toFixed(1)} KB`,
148→				);
149→				if (stderr) {
150→					claudeLogger.log(
151→						`stderr size: ${(stderr.length / 1024).toFixed(1)} KB`,
152→					);
153→				}
154→			}
155→
156→			if (exitCode !== 0) {
157→				const exitCodeExplanation = this.getExitCodeExplanation(exitCode);
158→				const errorDetails = [
159→					`Claude CLI exited with code ${exitCode}${exitCodeExplanation}`,
160→					stderr ? `stderr: ${stderr.trim()}` : null,
161→					stdout
162→						? `stdout preview: ${stdout.substring(0, 500)}`
163→						: "(no stdout)",
164→				]
165→					.filter(Boolean)
166→					.join("\n");
167→				throw new Error(errorDetails);
168→			}
169→
170→			return this.parseJsonResponse(stdout, verbose);
171→		} catch (err) {
172→			if (progressInterval) clearInterval(progressInterval);
173→
174→			const message = err instanceof Error ? err.message : String(err);
175→			if (message.includes("ENOENT")) {
176→				throw new Error(
177→					`Claude CLI not found. Is 'claude' installed and in your PATH? Original error: ${message}`,
178→				);
179→			} else if (message.includes("EACCES")) {
180→				throw new Error(
181→					`Permission denied when running Claude CLI. Check file permissions. Original error: ${message}`,
182→				);
183→			} else if (message.includes("E2BIG")) {
184→				throw new Error(
185→					`Prompt too large for Claude CLI. The prompt exceeds OS argument size limits. Original error: ${message}`,
186→				);
187→			}
188→			throw err;
189→		}
190→	}
191→
192→	/**
193→	 * Normalize Claude CLI response to standard format
194→	 */
195→	protected normalizeResponse(parsed: unknown): IProviderResponse {
196→		// Handle case where Claude returns array directly (evaluator responses)
