278→			);
279→			if (lines.length > 1) {
280→				console.log(
281→					`[${this.displayName}] Last line preview: ${lines[lines.length - 1]!.substring(0, 100)}${lines[lines.length - 1]!.length > 100 ? "..." : ""}`,
282→				);
283→			}
284→		}
285→
