303→				console.log(
304→					`[${this.displayName}] Found JSON-like lines without "type" field - may be legacy format`,
305→				);
306→			}
307→		}
308→
309→		// If we found NDJSON streaming events, parse them
310→		if (ndjsonLines.length > 0) {
311→			if (verbose) {
312→				console.log(
313→					`[${this.displayName}] Detected NDJSON streaming format (${ndjsonLines.length} events out of ${lines.length} lines)`,
314→				);
315→			}
316→			return this.parseNdjsonResponse(ndjsonLines, verbose);
317→		}
318→
319→		// Fall back to standard JSON parsing
320→		if (verbose && stdout.trim().length === 0) {
321→			console.log(
322→				`[${this.displayName}] ⚠️  Attempting to parse empty stdout - will return empty result`,
323→			);
324→		}
325→		return super.parseJsonResponse(stdout, verbose);
326→	}
