328→	/**
329→	 * Parse NDJSON streaming response format
330→	 * Extracts text from "text" events and metadata from "step_finish" events
331→	 */
332→	private parseNdjsonResponse(
333→		lines: string[],
334→		verbose: boolean,
335→	): IProviderResponse {
336→		const textParts: string[] = [];
337→		let sessionId: string | undefined;
338→		let cost: number | undefined;
339→		let usage: Usage | undefined;
340→
341→		for (const line of lines) {
342→			try {
343→				const event = JSON.parse(line) as OpenCodeStreamEvent;
344→
345→				switch (event.type) {
346→					case "text":
347→						// Extract text content from text events
348→						if (event.part?.text) {
349→							textParts.push(event.part.text);
350→						}
351→						if (!sessionId && event.sessionID) {
352→							sessionId = event.sessionID;
353→						}
354→						break;
355→
356→					case "step_finish":
357→						// Extract cost and usage from step_finish events
358→						if (event.part?.cost !== undefined) {
359→							cost = event.part.cost;
360→						}
361→						if (event.part?.tokens) {
362→							usage = {
363→								input_tokens: event.part.tokens.input ?? 0,
364→								output_tokens: event.part.tokens.output ?? 0,
365→								cache_creation_input_tokens:
366→									event.part.tokens.cache?.write ?? 0,
367→								cache_read_input_tokens: event.part.tokens.cache?.read ?? 0,
368→							};
369→						}
370→						if (!sessionId && event.sessionID) {
371→							sessionId = event.sessionID;
372→						}
373→						break;
374→
375→					case "step_start":
376→						// Extract session ID from step_start if not already set
377→						if (!sessionId && event.sessionID) {
378→							sessionId = event.sessionID;
379→						}
380→						break;
381→				}
382→			} catch {
383→				// Skip malformed lines
384→				if (verbose) {
385→					console.log(
386→						`[${this.displayName}] Skipping malformed NDJSON line: ${line.substring(0, 50)}...`,
387→					);
388→				}
389→			}
390→		}
391→
392→		const result = textParts.join("");
393→
394→		if (verbose) {
395→			console.log(
396→				`[${this.displayName}] ✓ Parsed NDJSON: ${textParts.length} text events, result length: ${result.length} chars`,
397→			);
398→			if (cost !== undefined) {
399→				console.log(`[${this.displayName}] Cost: $${cost.toFixed(6)}`);
400→			}
401→		}
402→
403→		return {
404→			result,
405→			session_id: sessionId,
406→			cost_usd: cost,
407→			usage,
408→		};
409→	}
410→
411→	/**
412→	 * Normalize OpenCode CLI response to standard format (legacy single JSON)
413→	 */
414→	protected normalizeResponse(parsed: unknown): IProviderResponse {
415→		// Handle case where OpenCode returns array directly
416→		if (Array.isArray(parsed)) {
417→			return { result: JSON.stringify(parsed) };
418→		}
419→
420→		const openCodeResponse = parsed as OpenCodeCLIResponse;
421→
422→		// OpenCode may use different field names - handle various possibilities
423→		const result =
424→			openCodeResponse.result ??
425→			openCodeResponse.output ??
426→			openCodeResponse.content ??
427→			"";
428→
429→		const cost_usd =
430→			openCodeResponse.cost ?? openCodeResponse.total_cost ?? undefined;
431→
432→		const duration_ms =
433→			openCodeResponse.duration_ms ?? openCodeResponse.duration ?? undefined;
434→
435→		// Normalize usage format
436→		let usage: Usage | undefined;
437→		if (openCodeResponse.usage) {
438→			usage = {
439→				input_tokens: openCodeResponse.usage.input_tokens ?? 0,
440→				output_tokens: openCodeResponse.usage.output_tokens ?? 0,
441→				cache_creation_input_tokens: 0,
442→				cache_read_input_tokens: 0,
443→			};
444→		}
445→
446→		return {
447→			result,
448→			session_id: openCodeResponse.session_id,
449→			cost_usd,
450→			duration_ms,
451→			usage,
452→		};
453→	}
454→}
