 10→/**
 11→ * Represents an extracted Markdown link
 12→ */
 13→export interface IExtractedLink {
 14→	/** Raw link target as written in the source */
 15→	rawPath: string;
 16→	/** Resolved absolute path */
 17→	absolutePath: string;
 18→	/** Link text/label */
 19→	linkText: string;
 20→	/** Source file containing the link */
 21→	sourcePath: string;
 22→}
 23→
 24→/**
 25→ * Options for linked docs discovery
 26→ */
 27→export interface IDocDiscoveryOptions {
 28→	/** AI provider for summarization */
 29→	provider: IAIProvider;
 30→	/** Enable verbose logging */
 31→	verbose?: boolean;
 32→	/** Maximum number of docs to summarize (default: 30) */
 33→	maxDocs?: number;
 34→	/** Maximum content length per file before truncation (default: 8000) */
 35→	maxContentLength?: number;
 36→	/** Concurrency for summarization calls (default: 3) */
 37→	concurrency?: number;
 38→	/** Timeout in milliseconds for AI provider calls (default: 60000) */
 39→	timeout?: number;
 40→}
 41→
 42→/**
 43→ * Result of linked docs discovery
 44→ */
 45→export interface ILinkedDocsResult {
 46→	/** Discovered and summarized documentation */
 47→	docs: ILinkedDocSummary[];
 48→	/** Total links found before filtering */
 49→	totalLinksFound: number;
 50→	/** Links that couldn't be resolved (file not found) */
 51→	unresolvedLinks: string[];
 52→}
 53→
 54→// Regex patterns for Markdown links
 55→// Inline: [text](path/to/file.md) or [text](path/to/file.md#anchor)
 56→const INLINE_LINK_REGEX = /\[([^\]]+)\]\(([^)]+\.md(?:#[^)]*)?)\)/gi;
 57→
 58→// Reference definition: [ref]: path/to/file.md
 59→const REFERENCE_DEF_REGEX = /^\[([^\]]+)\]:\s*(\S+\.md(?:#\S*)?)\s*$/gim;
 60→
 61→/**
 62→ * Check if a path is an external URL
 63→ */
 64→function isExternalUrl(path: string): boolean {
 65→	return (
 66→		path.startsWith("http://") ||
 67→		path.startsWith("https://") ||
 68→		path.startsWith("//")
 69→	);
 70→}
 71→
 72→/**
 73→ * Check if a path is an anchor-only link
 74→ */
 75→function isAnchorOnly(path: string): boolean {
 76→	return path.startsWith("#");
 77→}
 78→
 79→/**
 80→ * Check if a path is a self-reference to AGENTS.md, CLAUDE.md, copilot-instructions.md,
 81→ * or *.instructions.md files in .github/instructions/
 82→ */
 83→function isSelfReference(path: string): boolean {
 84→	const filename = path.split("/").pop()?.split("#")[0]?.toLowerCase() ?? "";
 85→
 86→	// Original patterns
 87→	if (
 88→		filename === "agents.md" ||
 89→		filename === "claude.md" ||
 90→		filename === "copilot-instructions.md"
 91→	) {
 92→		return true;
 93→	}
 94→
 95→	// New pattern: *.instructions.md in .github/instructions/ directory
 96→	if (
 97→		filename.endsWith(".instructions.md") &&
 98→		path.includes(".github/instructions/")
 99→	) {
100→		return true;
101→	}
102→
103→	return false;
104→}
105→
106→/**
107→ * Remove anchor fragment from path
108→ */
109→function removeAnchor(path: string): string {
110→	return path.split("#")[0] ?? path;
111→}
112→
113→/**
114→ * Extract Markdown links to .md files from content.
115→ * Handles: [text](path.md), [text](path.md#anchor), [ref]: path.md
116→ * Excludes: external URLs, anchor-only links, self-references
117→ *
118→ * @param content - Markdown content to parse
119→ * @param sourcePath - Absolute path to the source file
120→ * @returns Array of extracted links with resolved paths
121→ */
122→export function extractMarkdownLinks(
123→	content: string,
124→	sourcePath: string,
125→): IExtractedLink[] {
126→	const links: IExtractedLink[] = [];
127→	const sourceDir = dirname(sourcePath);
128→	const seenPaths = new Set<string>();
129→
130→	// Process inline links: [text](path.md)
131→	let match: RegExpExecArray | null;
132→	INLINE_LINK_REGEX.lastIndex = 0;
133→	while ((match = INLINE_LINK_REGEX.exec(content)) !== null) {
134→		const linkText = match[1] ?? "";
135→		const rawPath = match[2] ?? "";
136→
137→		if (!rawPath || isExternalUrl(rawPath) || isAnchorOnly(rawPath)) {
138→			continue;
139→		}
140→
141→		const cleanPath = removeAnchor(rawPath);
142→
143→		if (isSelfReference(cleanPath)) {
144→			continue;
145→		}
146→
147→		// Resolve relative path
148→		const absolutePath = isAbsolute(cleanPath)
149→			? cleanPath
150→			: resolve(sourceDir, cleanPath);
151→
152→		// Deduplicate
153→		if (seenPaths.has(absolutePath)) {
154→			continue;
155→		}
156→		seenPaths.add(absolutePath);
157→
158→		links.push({
159→			rawPath: cleanPath,
160→			absolutePath,
161→			linkText,
162→			sourcePath,
163→		});
164→	}
165→
166→	// Process reference definitions: [ref]: path.md
167→	REFERENCE_DEF_REGEX.lastIndex = 0;
168→	while ((match = REFERENCE_DEF_REGEX.exec(content)) !== null) {
169→		const linkText = match[1] ?? "";
170→		const rawPath = match[2] ?? "";
171→
172→		if (!rawPath || isExternalUrl(rawPath) || isAnchorOnly(rawPath)) {
173→			continue;
174→		}
175→
176→		const cleanPath = removeAnchor(rawPath);
177→
178→		if (isSelfReference(cleanPath)) {
179→			continue;
180→		}
181→
182→		const absolutePath = isAbsolute(cleanPath)
183→			? cleanPath
184→			: resolve(sourceDir, cleanPath);
185→
186→		if (seenPaths.has(absolutePath)) {
187→			continue;
188→		}
189→		seenPaths.add(absolutePath);
190→
191→		links.push({
192→			rawPath: cleanPath,
193→			absolutePath,
194→			linkText,
195→			sourcePath,
196→		});
197→	}
198→
199→	return links;
200→}
201→
202→/**
203→ * Build the summarization prompt for a documentation file.
204→ * Note: File path is intentionally omitted to prevent AI agents from
205→ * attempting to explore/read the file instead of just summarizing the content.
206→ */
207→function buildSummarizationPrompt(content: string): string {
208→	return `You are a documentation summarizer for AI coding agents.
209→
210→Given the following Markdown documentation, provide a single detailed sentence that describes both the document's purpose and the key information it contains for developers/AI agents.
211→
212→IMPORTANT:
213→- Respond with ONLY 1 detailed sentence, nothing else
214→- Be specific and actionable, avoid vague statements
215→- Focus on information useful for coding tasks
216→
217→---
218→
219→\`\`\`markdown
220→${content}
221→\`\`\``;
222→}
223→
224→/**
225→ * Generate a single detailed sentence summary for a documentation file.
226→ *
227→ * Uses isolated prompt execution to prevent AI agents from exploring
228→ * the filesystem instead of just summarizing the provided content.
229→ *
230→ * @param relativePath - Relative path for display (used in fallback message only)
231→ * @param content - File content to summarize
232→ * @param provider - AI provider for summarization
233→ * @param timeout - Timeout in milliseconds (default: 60000)
234→ * @returns Summary string (1 detailed sentence)
235→ */
236→export async function summarizeDocFile(
237→	relativePath: string,
238→	content: string,
239→	provider: IAIProvider,
240→	timeout?: number,
241→): Promise<string> {
242→	const prompt = buildSummarizationPrompt(content);
243→
244→	try {
245→		// Use isolated execution to prevent file exploration
246→		const response = await invokeIsolated(provider, prompt, {
247→			timeout: timeout ?? DEFAULT_TIMEOUT_MS,
248→		});
249→
250→		// Clean up the response - remove any extra whitespace/newlines
251→		const summary = response.result.trim();
252→
253→		// Validate it looks like a summary (has some content)
254→		if (summary.length < 10) {
255→			return `Documentation file at ${relativePath}. Summary unavailable.`;
256→		}
257→
258→		return summary;
259→	} catch (_error) {
260→		// Fallback on error
261→		return `Documentation file at ${relativePath}. Summary unavailable.`;
262→	}
263→}
264→
265→/**
266→ * Read file content with optional truncation
267→ */
268→async function readFileWithLimit(
269→	filePath: string,
270→	maxLength: number,
271→): Promise<string | null> {
272→	try {
273→		const content = await readFile(filePath, "utf-8");
274→
275→		if (content.length > maxLength) {
276→			// Truncate at a newline boundary if possible
277→			const truncated = content.slice(0, maxLength);
278→			const lastNewline = truncated.lastIndexOf("\n");
279→
280→			return lastNewline > maxLength * 0.8
281→				? `${truncated.slice(0, lastNewline)}\n\n[Content truncated...]`
282→				: `${truncated}\n\n[Content truncated...]`;
