								`[${this.displayName}] ⚠️  Error event: ${event.error.message}`,
							);
						}
						break;
				}
			} catch {
				// Skip malformed lines
				if (verbose) {
					console.log(
						`[${this.displayName}] Skipping malformed NDJSON line: ${line.substring(0, 50)}...`,
					);
				}
			}
		}

